// ministerioRefatoracaoService.ts
// Servico de Refatoracao Inteligente de Ministerios - DiakoniaApp

import { supabase } from "@/integrations/supabase/client";

export interface MinisterioExistente {
  id: string;
    nome: string;
      sigla: string | null;
        descricao: string | null;
          lider_id: string | null;
            co_lider_id: string | null;
              ativo: boolean;
              }

              export interface MinisterioExtraido {
                nome: string;
                  sigla?: string;
                    descricao?: string;
                      responsabilidades?: string;
                        base_institucional?: string;
                          referencia_documento?: string;
                            nivel?: string;
                            }

                            export type AcaoRefatoracao = "update" | "create" | "manter";

                            export interface DifCampo {
                              campo: string;
                                label: string;
                                  valorAtual: string | null;
                                    valorNovo: string | null;
                                      tipo: "novo" | "modificado" | "sem_mudanca";
                                      }

                                      export interface ItemComparacao {
                                        acao: AcaoRefatoracao;
                                          existente: MinisterioExistente | null;
                                            extraido: MinisterioExtraido;
                                              diferencas: DifCampo[];
                                                similaridade: number;
                                                }

                                                export interface ResultadoRefatoracao {
                                                  paraCriar: ItemComparacao[];
                                                    paraAtualizar: ItemComparacao[];
                                                      paraManter: ItemComparacao[];
                                                        orfaos: MinisterioExistente[];
                                                        }

                                                        // --- Normalizacao ---

                                                        export function normalize(text: string): string {
                                                          return text
                                                              .toLowerCase()
                                                                  .normalize("NFD")
                                                                      .replace(/[\u0300-\u036f]/g, "")
                                                                          .replace(/[^a-z0-9\s]/g, " ")
                                                                              .replace(/\s+/g, " ")
                                                                                  .trim();
                                                                                  }

                                                                                  export function calcularSimilaridade(a: string, b: string): number {
                                                                                    const na = normalize(a);
                                                                                      const nb = normalize(b);
                                                                                        if (na === nb) return 100;
                                                                                          if (na.includes(nb) || nb.includes(na)) return 85;
                                                                                            const wordsA = new Set(na.split(" ").filter(w => w.length > 2));
                                                                                              const wordsB = new Set(nb.split(" ").filter(w => w.length > 2));
                                                                                                const intersection = [...wordsA].filter(w => wordsB.has(w));
                                                                                                  const union = new Set([...wordsA, ...wordsB]);
                                                                                                    if (union.size === 0) return 0;
                                                                                                      const jaccardScore = (intersection.length / union.size) * 100;
                                                                                                        const boost = na.split(" ")[0] === nb.split(" ")[0] ? 10 : 0;
                                                                                                          return Math.min(100, Math.round(jaccardScore + boost));
                                                                                                          }
                                                                                                          
                                                                                                          // --- Match Inteligente ---
                                                                                                          
                                                                                                          const THRESHOLD_MATCH = 60;
                                                                                                          
                                                                                                          export function matchMinisterios(
                                                                                                            existentes: MinisterioExistente[],
                                                                                                              extraidos: MinisterioExtraido[]
                                                                                                              ): Map<MinisterioExtraido, MinisterioExistente | null> {
                                                                                                                const resultado = new Map<MinisterioExtraido, MinisterioExistente | null>();
                                                                                                                  const usados = new Set<string>();
                                                                                                                  
                                                                                                                    for (const ext of extraidos) {
                                                                                                                        let melhorMatch: MinisterioExistente | null = null;
                                                                                                                            let melhorScore = 0;
                                                                                                                                for (const ex of existentes) {
                                                                                                                                      if (usados.has(ex.id)) continue;
                                                                                                                                            const score = calcularSimilaridade(ext.nome, ex.nome);
                                                                                                                                                  if (score > melhorScore && score >= THRESHOLD_MATCH) {
                                                                                                                                                          melhorScore = score;
                                                                                                                                                                  melhorMatch = ex;
                                                                                                                                                                        }
                                                                                                                                                                            }
                                                                                                                                                                                if (melhorMatch) usados.add(melhorMatch.id);
                                                                                                                                                                                    resultado.set(ext, melhorMatch);
                                                                                                                                                                                      }
                                                                                                                                                                                        return resultado;
                                                                                                                                                                                        }
                                                                                                                                                                                        
                                                                                                                                                                                        export function encontrarOrfaos(
                                                                                                                                                                                          existentes: MinisterioExistente[],
                                                                                                                                                                                            matchMap: Map<MinisterioExtraido, MinisterioExistente | null>
                                                                                                                                                                                            ): MinisterioExistente[] {
                                                                                                                                                                                              const matched = new Set<string>();
                                                                                                                                                                                                matchMap.forEach((ex) => { if (ex) matched.add(ex.id); });
                                                                                                                                                                                                  return existentes.filter(e => !matched.has(e.id));
                                                                                                                                                                                                  }
                                                                                                                                                                                                  
                                                                                                                                                                                                  // --- Enriquecimento ---
                                                                                                                                                                                                  
                                                                                                                                                                                                  function montarDescricaoEnriquecida(ext: MinisterioExtraido): string | null {
                                                                                                                                                                                                    const partes: string[] = [];
                                                                                                                                                                                                      if (ext.descricao) partes.push(ext.descricao);
                                                                                                                                                                                                        if (ext.responsabilidades) partes.push("Responsabilidades: " + ext.responsabilidades);
                                                                                                                                                                                                          if (ext.base_institucional) partes.push("Base: " + ext.base_institucional);
                                                                                                                                                                                                            return partes.length > 0 ? partes.join("\n\n") : null;
                                                                                                                                                                                                            }
                                                                                                                                                                                                            
                                                                                                                                                                                                            export function calcularDiferencas(
                                                                                                                                                                                                              existente: MinisterioExistente,
                                                                                                                                                                                                                extraido: MinisterioExtraido
                                                                                                                                                                                                                ): DifCampo[] {
                                                                                                                                                                                                                  const difs: DifCampo[] = [];
                                                                                                                                                                                                                    const descricaoNova = montarDescricaoEnriquecida(extraido);
                                                                                                                                                                                                                    
                                                                                                                                                                                                                      const campos = [
                                                                                                                                                                                                                          { campo: "sigla", label: "Sigla", valorNovo: extraido.sigla ?? null },
                                                                                                                                                                                                                              { campo: "descricao", label: "Descricao", valorNovo: descricaoNova },
                                                                                                                                                                                                                                ];
                                                                                                                                                                                                                                
                                                                                                                                                                                                                                  for (const { campo, label, valorNovo } of campos) {
                                                                                                                                                                                                                                      const valorAtual = (existente as Record<string, unknown>)[campo] as string | null ?? null;
                                                                                                                                                                                                                                          if (!valorNovo) continue;
                                                                                                                                                                                                                                              if (!valorAtual) {
                                                                                                                                                                                                                                                    difs.push({ campo, label, valorAtual: null, valorNovo, tipo: "novo" });
                                                                                                                                                                                                                                                        } else if (valorNovo.length > valorAtual.length + 20) {
                                                                                                                                                                                                                                                              difs.push({ campo, label, valorAtual, valorNovo, tipo: "modificado" });
                                                                                                                                                                                                                                                                  } else {
                                                                                                                                                                                                                                                                        difs.push({ campo, label, valorAtual, valorNovo: valorAtual, tipo: "sem_mudanca" });
                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                return difs;
                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                export function enriquecerDados(
                                                                                                                                                                                                                                                                                  existente: MinisterioExistente,
                                                                                                                                                                                                                                                                                    extraido: MinisterioExtraido
                                                                                                                                                                                                                                                                                    ): Partial<MinisterioExistente> {
                                                                                                                                                                                                                                                                                      const patch: Record<string, unknown> = {};
                                                                                                                                                                                                                                                                                        const difs = calcularDiferencas(existente, extraido);
                                                                                                                                                                                                                                                                                          for (const dif of difs) {
                                                                                                                                                                                                                                                                                              if (dif.tipo !== "sem_mudanca" && dif.valorNovo) {
                                                                                                                                                                                                                                                                                                    patch[dif.campo] = dif.valorNovo;
                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                            return patch as Partial<MinisterioExistente>;
                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                            // --- Analise Completa ---
                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                            export function analisarRefatoracao(
                                                                                                                                                                                                                                                                                                              existentes: MinisterioExistente[],
                                                                                                                                                                                                                                                                                                                extraidos: MinisterioExtraido[]
                                                                                                                                                                                                                                                                                                                ): ResultadoRefatoracao {
                                                                                                                                                                                                                                                                                                                  const matchMap = matchMinisterios(existentes, extraidos);
                                                                                                                                                                                                                                                                                                                    const orfaos = encontrarOrfaos(existentes, matchMap);
                                                                                                                                                                                                                                                                                                                      const paraCriar: ItemComparacao[] = [];
                                                                                                                                                                                                                                                                                                                        const paraAtualizar: ItemComparacao[] = [];
                                                                                                                                                                                                                                                                                                                          const paraManter: ItemComparacao[] = [];
                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                            matchMap.forEach((existente, extraido) => {
                                                                                                                                                                                                                                                                                                                                if (!existente) {
                                                                                                                                                                                                                                                                                                                                      paraCriar.push({ acao: "create", existente: null, extraido, diferencas: [], similaridade: 0 });
                                                                                                                                                                                                                                                                                                                                          } else {
                                                                                                                                                                                                                                                                                                                                                const similaridade = calcularSimilaridade(extraido.nome, existente.nome);
                                                                                                                                                                                                                                                                                                                                                      const diferencas = calcularDiferencas(existente, extraido);
                                                                                                                                                                                                                                                                                                                                                            const temMudancas = diferencas.some(d => d.tipo !== "sem_mudanca");
                                                                                                                                                                                                                                                                                                                                                                  if (temMudancas) {
                                                                                                                                                                                                                                                                                                                                                                          paraAtualizar.push({ acao: "update", existente, extraido, diferencas, similaridade });
                                                                                                                                                                                                                                                                                                                                                                                } else {
                                                                                                                                                                                                                                                                                                                                                                                        paraManter.push({ acao: "manter", existente, extraido, diferencas, similaridade });
                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                                                                                                                                                                    });
                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                      return { paraCriar, paraAtualizar, paraManter, orfaos };
                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                      // --- Extracao de Estrutura ---
                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                      export async function extractStructureFromText(): Promise<MinisterioExtraido[]> {
                                                                                                                                                                                                                                                                                                                                                                                                        const { data, error } = await supabase
                                                                                                                                                                                                                                                                                                                                                                                                            .from("documento_estrutura")
                                                                                                                                                                                                                                                                                                                                                                                                                .select("*")
                                                                                                                                                                                                                                                                                                                                                                                                                    .eq("ativo", true)
                                                                                                                                                                                                                                                                                                                                                                                                                        .eq("tipo", "ministerio")
                                                                                                                                                                                                                                                                                                                                                                                                                            .order("ordem");
                                                                                                                                                                                                                                                                                                                                                                                                                              if (error) throw new Error("Erro ao buscar estrutura: " + error.message);
                                                                                                                                                                                                                                                                                                                                                                                                                                return (data ?? []).map((item: Record<string, unknown>) => ({
                                                                                                                                                                                                                                                                                                                                                                                                                                    nome: item.nome as string,
                                                                                                                                                                                                                                                                                                                                                                                                                                        descricao: (item.descricao as string) ?? undefined,
                                                                                                                                                                                                                                                                                                                                                                                                                                            responsabilidades: (item.responsabilidades as string) ?? undefined,
                                                                                                                                                                                                                                                                                                                                                                                                                                                base_institucional: (item.base_institucional as string) ?? undefined,
                                                                                                                                                                                                                                                                                                                                                                                                                                                    referencia_documento: (item.referencia_documento as string) ?? undefined,
                                                                                                                                                                                                                                                                                                                                                                                                                                                        nivel: (item.nivel as string) ?? undefined,
                                                                                                                                                                                                                                                                                                                                                                                                                                                          }));
                                                                                                                                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                          export async function extractStructureWithAI(): Promise<MinisterioExtraido[]> {
                                                                                                                                                                                                                                                                                                                                                                                                                                                            const { data: secoes, error } = await supabase
                                                                                                                                                                                                                                                                                                                                                                                                                                                                .from("secoes_documento")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                    .select("titulo, conteudo, ministerio_ref, tipo_secao")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        .in("tipo_secao", ["ministerio", "diretoria"])
                                                                                                                                                                                                                                                                                                                                                                                                                                                                            .order("ordem");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                              if (error) throw new Error("Erro ao buscar secoes: " + error.message);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const ministeriosIA: MinisterioExtraido[] = [];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const nomesBuscados = new Set<string>();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    for (const secao of (secoes ?? []) as Record<string, unknown>[]) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const nome = (secao.ministerio_ref as string) || (secao.titulo as string);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (!nome || nomesBuscados.has(normalize(nome))) continue;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                nomesBuscados.add(normalize(nome));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const { data } = await supabase.rpc("buscar_modelo_ministerio", { p_nome: nome });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const d = data as Record<string, string> | null;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      ministeriosIA.push({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              nome: d?.nome || nome,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      descricao: d?.descricao || (secao.conteudo as string) || undefined,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              responsabilidades: d?.responsabilidades || undefined,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      base_institucional: d?.base_institucional || undefined,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              referencia_documento: (secao.titulo as string) || undefined,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        } catch {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ministeriosIA.push({ nome, descricao: (secao.conteudo as string) || undefined });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      return ministeriosIA;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      export async function extrairEstrutura(): Promise<{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ministerios: MinisterioExtraido[];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          fonte: "ia" | "parser" | "combinado";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }> {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            let iaMin: MinisterioExtraido[] = [];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              let parserMin: MinisterioExtraido[] = [];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                try { iaMin = await extractStructureWithAI(); } catch { /* fallback */ }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  try { parserMin = await extractStructureFromText(); } catch { /* fallback */ }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const todos = [...iaMin];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const nomesIA = new Set(iaMin.map(m => normalize(m.nome)));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        for (const p of parserMin) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (!nomesIA.has(normalize(p.nome))) todos.push(p);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const fonte =
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    iaMin.length > 0 && parserMin.length > 0 ? "combinado" :
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        iaMin.length > 0 ? "ia" : "parser";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          return { ministerios: todos, fonte };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          // --- Aplicacao e Historico ---
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          export async function salvarHistoricoRefatoracao(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ministerios: MinisterioExistente[],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              usuarioEmail: string | null,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                totalCriados: number,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  totalAtualizados: number,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    totalMantidos: number
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ): Promise<void> {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const snapshot = {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          executado_em: new Date().toISOString(),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              executado_por: usuarioEmail,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  total_criados: totalCriados,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      total_atualizados: totalAtualizados,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          total_mantidos: totalMantidos,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ministerios_snapshot: ministerios.map(m => ({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    id: m.id, nome: m.nome, sigla: m.sigla, descricao: m.descricao, ativo: m.ativo,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        })),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            await supabase.from("documentos_historico").insert({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                documento_id: null,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    acao: "refatoracao_ministerios",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        usuario_email: usuarioEmail,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            observacao: JSON.stringify(snapshot),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              export async function aplicarItemRefatoracao(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                item: ItemComparacao,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  acao: "atualizar" | "criar",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    usuarioEmail: string | null
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ): Promise<void> {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      if (acao === "atualizar" && item.existente) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const patch = enriquecerDados(item.existente, item.extraido);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              if (Object.keys(patch).length === 0) return;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const { error } = await supabase.from("ministerios").update(patch).eq("id", item.existente.id);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      if (error) throw new Error("Erro ao atualizar: " + error.message);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          await supabase.from("documentos_historico").insert({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                documento_id: null,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      acao: "ministerio_enriquecido",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            usuario_email: usuarioEmail,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  titulo_doc: item.existente.nome,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        observacao: "Campos enriquecidos: " + Object.keys(patch).join(", "),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (acao === "criar") {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const novo = {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          nome: item.extraido.nome,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                sigla: item.extraido.sigla || null,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      descricao: montarDescricaoEnriquecida(item.extraido),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ativo: true,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const { error } = await supabase.from("ministerios").insert(novo);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (error) throw new Error("Erro ao criar: " + error.message);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            await supabase.from("documentos_historico").insert({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  documento_id: null,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        acao: "ministerio_criado_via_documento",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              usuario_email: usuarioEmail,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    titulo_doc: item.extraido.nome,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          observacao: "Criado a partir de estrutura documental",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
